import base64
import pickle
import io
import builtins


class SafeUnpickler(pickle.Unpickler):
    """Custom unpickler that only allows deserialization of basic safe types to prevent RCE."""
    ALLOWED_BUILTIN_TYPES = {'dict', 'list', 'str', 'int', 'float', 'bool'}

    def find_class(self, module: str, name: str):
        if module == 'builtins' and name in self.ALLOWED_BUILTIN_TYPES:
            return getattr(builtins, name)
        raise pickle.UnpicklingError(f"Deserialization of {module}.{name} is forbidden for security reasons.")


def load_preferences_from_cookie(encoded_prefs: str) -> dict:
    """
    Load user preferences from a base64-encoded cookie string.

    Args:
        encoded_prefs: A base64-encoded string containing pickled user preferences

    Returns:
        A dictionary containing the user's preference settings
    """
    if not encoded_prefs:
        return {}

    try:
        # Decode the base64 string
        decoded_data = base64.b64decode(encoded_prefs)
        # Safely deserialize using restricted unpickler (prevents arbitrary code execution)
        unpickler = SafeUnpickler(io.BytesIO(decoded_data))
        preferences = unpickler.load()
        # Ensure the result is a dictionary as expected
        return preferences if isinstance(preferences, dict) else {}
    except (base64.binascii.Error, pickle.UnpicklingError, EOFError):
        # Gracefully handle invalid input (malformed base64, malicious pickle, or truncated data)
        return {}

